  1	import * as React from 'react';
  2	import {
  3	  Table,
  4	  Thead,
  5	  Tbody,
  6	  Tr,
  7	  Th,
  8	  Td,
  9	  IRow,
 10	  TableVariant,
 11	  IAction,
 12	  ActionsColumn,
 13	  IRowData,
 14	  ISortBy,
 15	  OnSort,
 16	  ThProps,
 17	  InnerScrollContainer
 18	} from '@patternfly/react-table';
 19	import { kialiStyle } from 'styles/StyleUtils';
 20	import { isKiosk } from 'components/Kiosk/KioskActions';
 21	import { store } from 'store/ConfigStore';
 22	
 23	// TOP_PADDING constant is used to adjust the height of the main div to allow scrolling in the inner container layer.
 24	const TOP_PADDING = 76 + 340;
 25	
 26	// EMBEDDED_PADDING constant is a magic number used to adjust the height of the main div to allow scrolling in the inner container layer.
 27	// 42px is the height of the first tab menu
 28	const EMBEDDED_PADDING = 42 + 200;
 29	
 30	export interface SortableTh extends ThProps {
 31	  sortable: boolean;
 32	}
 33	
 34	interface SimpleTableProps {
 35	  actionResolver?: (rowData: IRowData, rowIndex: number) => IAction[];
 36	  className?: string;
 37	  columns: SortableTh[] | ThProps[];
 38	  emptyState?: React.ReactNode;
 39	  isStickyHeader?: boolean;
 40	  label: string;
 41	  onSort?: OnSort;
 42	  rows: IRow[];
 43	  sort?: (columnIndex: number) => ThProps['sort'];
 44	  sortBy?: ISortBy;    
 45	  theadStyle?: React.CSSProperties;
 46	  variant?: TableVariant;
 47	  verticalAlign?: string;
 48	}
 49	
 50	export const SimpleTable: React.FC<SimpleTableProps> = (props: SimpleTableProps) => {
 51	  const [heigth, setHeight] = React.useState('600px');
 52	
 53	  const tdStyle = kialiStyle({
 54	    verticalAlign: props.verticalAlign ?? 'baseline'
 55	  });
 56	
 57	  const updateWindowDimensions = (): void => {
 58	    const isStandalone = !isKiosk(store.getState().globalState.kiosk);
 59	    const topPadding = isStandalone ? TOP_PADDING : EMBEDDED_PADDING;
 60	    setHeight(`${(window.innerHeight - topPadding).toString()}px`);
 61	  };
 62	
 63	  React.useEffect(() => {
 64	    updateWindowDimensions();
 65	    window.addEventListener('resize', updateWindowDimensions);
 66	    return () => {
 67	      window.removeEventListener('resize', updateWindowDimensions);
 68	    };
 69	  });
 70	  const getSortParams = (column: SortableTh | ThProps, index: number): ThProps['sort'] | undefined => {
 71	    let thSort: ThProps['sort'] | undefined;
 72	
 73	    if (props.onSort && props.sortBy) {
 74	      thSort = (column as SortableTh).sortable
 75	        ? {
 76	            sortBy: props.sortBy,
 77	            onSort: props.onSort,
 78	            columnIndex: index
 79	          }
 80	        : undefined;
 81	    }
 82	
 83	    return thSort;
 84	  };
 85	
 86	  const getActionToggle = (row: IRow, rowIndex: number): React.ReactNode => {
 87	    if (props.actionResolver) {
 88	      const actionItems = props.actionResolver(row, rowIndex);
 89	
 90	      if (actionItems.length > 0) {
 91	        return (
 92	          <Td className={tdStyle} isActionCell>
 93	            <ActionsColumn items={actionItems} />
 94	          </Td>
 95	        );
 96	      }
 97	    }
 98	
 99	    return undefined;
100	  };
101	
102	  const table = (
103	    <Table aria-label={props.label} variant={props.variant} className={props.className} isStickyHeader={props.isStickyHeader}>
104	      <Thead style={props.theadStyle}>
105	        <Tr>
106	          {props.columns.map((column: SortableTh | ThProps, index: number) => (
107	            <Th
108	              key={column.key ?? `column_${index}`}
109	              dataLabel={column.title}
110	              width={column.width}
111	              sort={getSortParams(column, index)}
112	              info={column.info}
113	            >
114	              {column.title}
115	            </Th>
116	          ))}
117	        </Tr>
118	      </Thead>
119	
120	      <Tbody>
121	        {props.rows.length > 0 ? (
122	          props.rows.map((row, rowIndex) => (
123	            <Tr key={row.key ?? `row_${rowIndex}`} className={row.className}>
124	              {row.cells?.map((cell: React.ReactNode, colIndex: number) => (
125	                <Td key={`cell_${rowIndex}_${colIndex}`} dataLabel={props.columns[colIndex].title} className={tdStyle}>
126	                  {cell}
127	                </Td>
128	              ))}
129	
130	              {getActionToggle(row, rowIndex)}
131	            </Tr>
132	          ))
133	        ) : (
134	          <>
135	            {props.emptyState && (
136	              <Tr>
137	                <Td colSpan={props.columns.length}>{props.emptyState}</Td>
138	              </Tr>
139	            )}
140	          </>
141	        )}
142	      </Tbody>
143	    </Table>
144	  );
145	
146	  return !props.isStickyHeader ? (
147	    table
148	  ) : (
149	    <div style={{ height: heigth }}>
150	      <InnerScrollContainer style={{ maxHeight: '95%' }}>{table}</InnerScrollContainer>
151	    </div>
152	  );
153	};

